import{_ as t,c as i,o as e,a1 as o}from"./chunks/framework.DILC4Csi.js";const f=JSON.parse('{"title":"FAQ: OAuth Аутентификация и Диагностика Моделей | Antigravity Auth","description":"Узнайте о частых проблемах и решениях плагина Antigravity Auth. Включает руководства по диагностике сбоев OAuth аутентификации, обработке ошибок «модель не найдена», настройке совместимости плагинов и многое другое, помогающее быстро находить и решать любые возникающие проблемы.","frontmatter":{"title":"FAQ: OAuth Аутентификация и Диагностика Моделей | Antigravity Auth","sidebarTitle":"Что делать при сбое аутентификации","subtitle":"FAQ: OAuth Аутентификация и Диагностика Моделей","description":"Узнайте о частых проблемах и решениях плагина Antigravity Auth. Включает руководства по диагностике сбоев OAuth аутентификации, обработке ошибок «модель не найдена», настройке совместимости плагинов и многое другое, помогающее быстро находить и решать любые возникающие проблемы.","order":4},"headers":[],"relativePath":"ru/NoeFabris/opencode-antigravity-auth/faq/index.md","filePath":"ru/NoeFabris/opencode-antigravity-auth/faq/index.md"}'),r={name:"ru/NoeFabris/opencode-antigravity-auth/faq/index.md"};function l(n,a,d,h,u,s){return e(),i("div",null,[...a[0]||(a[0]=[o('<h1 id="часто-задаваемые-вопросы" tabindex="-1">Часто Задаваемые Вопросы <a class="header-anchor" href="#часто-задаваемые-вопросы" aria-label="Permalink to &quot;Часто Задаваемые Вопросы&quot;">​</a></h1><p>В этом разделе собраны наиболее часто встречающиеся проблемы при использовании плагина Antigravity Auth и их решения. Здесь вы найдете руководства по диагностике — от сбоев OAuth аутентификации до ошибок запросов к моделям и проблем совместимости плагинов.</p><h2 id="предварительные-условия" tabindex="-1">Предварительные Условия <a class="header-anchor" href="#предварительные-условия" aria-label="Permalink to &quot;Предварительные Условия&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">Перед началом убедитесь</p><ul><li>✅ <a href="./../start/quick-install/">Быстрая установка</a> выполнена и учетная запись успешно добавлена</li><li>✅ <a href="./../start/first-auth-login/">Первая аутентификация</a> выполнена и вы понимаете процесс OAuth</li></ul></div><h2 id="путь-обучения" tabindex="-1">Путь Обучения <a class="header-anchor" href="#путь-обучения" aria-label="Permalink to &quot;Путь Обучения&quot;">​</a></h2><p>Выберите соответствующее руководство по диагностике в зависимости от типа возникшей проблемы:</p><h3 id="_1-диагностика-сбоев-oauth-аутентификации" tabindex="-1">1. <a href="./common-auth-issues/">Диагностика Сбоев OAuth Аутентификации</a> <a class="header-anchor" href="#_1-диагностика-сбоев-oauth-аутентификации" aria-label="Permalink to &quot;1. [Диагностика Сбоев OAuth Аутентификации](./common-auth-issues/)&quot;">​</a></h3><p>Решение распространенных проблем с OAuth аутентификацией, обновлением токенов и учетными записями.</p><ul><li>Авторизация в браузере успешна, но терминал показывает &quot;сбой авторизации&quot;</li><li>Внезапная ошибка &quot;Permission Denied&quot; или &quot;invalid_grant&quot;</li><li>Сбой OAuth callback в браузере Safari</li><li>Невозможность завершить аутентификацию в средах WSL2/Docker</li></ul><h3 id="_2-миграция-учетных-записеи" tabindex="-1">2. <a href="./migration-guide/">Миграция Учетных Записей</a> <a class="header-anchor" href="#_2-миграция-учетных-записеи" aria-label="Permalink to &quot;2. [Миграция Учетных Записей](./migration-guide/)&quot;">​</a></h3><p>Миграция учетных записей между разными машинами и обработка обновлений версий.</p><ul><li>Перенос учетной записи со старого компьютера на новый</li><li>Понимание изменений форматов хранения (v1/v2/v3)</li><li>Исправление ошибки invalid_grant после миграции</li></ul><h3 id="_3-диагностика-модель-не-наидена" tabindex="-1">3. <a href="./model-not-found/">Диагностика &quot;Модель Не Найдена&quot;</a> <a class="header-anchor" href="#_3-диагностика-модель-не-наидена" aria-label="Permalink to &quot;3. [Диагностика &quot;Модель Не Найдена&quot;](./model-not-found/)&quot;">​</a></h3><p>Решение проблем, связанных с моделями — отсутствие моделей, ошибки 400 и т.д.</p><ul><li>Диагностика ошибки <code>Model not found</code></li><li>Исправление ошибки 400 <code>Invalid JSON payload received. Unknown name &quot;parameters&quot;</code></li><li>Исправление ошибок вызовов сервера MCP</li></ul><h3 id="_4-совместимость-плагинов" tabindex="-1">4. <a href="./plugin-compatibility/">Совместимость Плагинов</a> <a class="header-anchor" href="#_4-совместимость-плагинов" aria-label="Permalink to &quot;4. [Совместимость Плагинов](./plugin-compatibility/)&quot;">​</a></h3><p>Решение проблем совместимости с плагинами oh-my-opencode, DCP и другими.</p><ul><li>Правильная настройка порядка загрузки плагинов</li><li>Отключение конфликтующих методов аутентификации в oh-my-opencode</li><li>Включение смещения PID для сценариев параллельных агентов</li></ul><h3 id="_5-предупреждения-об-tos" tabindex="-1">5. <a href="./tos-warning/">Предупреждения об ToS</a> <a class="header-anchor" href="#_5-предупреждения-об-tos" aria-label="Permalink to &quot;5. [Предупреждения об ToS](./tos-warning/)&quot;">​</a></h3><p>Понимание рисков использования и предотвращение блокировки учетной записи.</p><ul><li>Ознакомление с ограничениями Terms of Service Google</li><li>Идентификация высокорискованных сценариев (новые учетные записи, интенсивные запросы)</li><li>Освоение лучших практик предотвращения блокировки учетных записей</li></ul><h2 id="быстрыи-поиск-проблем" tabindex="-1">Быстрый Поиск Проблем <a class="header-anchor" href="#быстрыи-поиск-проблем" aria-label="Permalink to &quot;Быстрый Поиск Проблем&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Симптом Ошибки</th><th>Рекомендуемое Чтение</th></tr></thead><tbody><tr><td>Сбой аутентификации, таймаут авторизации</td><td><a href="./common-auth-issues/">Диагностика Сбоев OAuth Аутентификации</a></td></tr><tr><td>invalid_grant, Permission Denied</td><td><a href="./common-auth-issues/">Диагностика Сбоев OAuth Аутентификации</a></td></tr><tr><td>Model not found, ошибка 400</td><td><a href="./model-not-found/">Диагностика &quot;Модель Не Найдена&quot;</a></td></tr><tr><td>Конфликт с другими плагинами</td><td><a href="./plugin-compatibility/">Совместимость Плагинов</a></td></tr><tr><td>Смена компьютера, обновление версии</td><td><a href="./migration-guide/">Миграция Учетных Записей</a></td></tr><tr><td>Обеспокоенность безопасностью учетной записи</td><td><a href="./tos-warning/">Предупреждения об ToS</a></td></tr></tbody></table><h2 id="следующии-шаг" tabindex="-1">Следующий Шаг <a class="header-anchor" href="#следующии-шаг" aria-label="Permalink to &quot;Следующий Шаг&quot;">​</a></h2><p>После решения проблемы вы можете:</p><ul><li>📖 Прочитать <a href="./../advanced/">Продвинутые Функции</a> для углубленного изучения многоаккаунтности, восстановления сессий и других возможностей</li><li>📚 Обратиться к <a href="./../appendix/">Приложениям</a> для ознакомления с архитектурным дизайном и полным справочником по конфигурации</li><li>🔄 Следить за <a href="./../changelog/">Журналом Изменений</a> для получения информации о последних функциях и изменениях</li></ul>',26)])])}const m=t(r,[["render",l]]);export{f as __pageData,m as default};
